#include <bits/stdc++.h>
using namespace std;

const int N=3e4+10;

int T,n,x[N*2],y[N*2],c[N],f[N],g[N];
long long ans;
char s[N];

struct Node{
    int sa[N],height[N],rk[N],f[N][15];
    void get_sa(){
        int m=26;
        for(int i=1;i<=m;i++) c[i]=0;
        for(int i=1;i<=n;i++) c[x[i]=s[i]-'a'+1]++;
        for(int i=2;i<=m;i++) c[i]+=c[i-1];
        for(int i=n;i;i--) sa[c[x[i]]--]=i;
        int num;
        for(int k=1;k<=n;k<<=1){
            num=0;
            for(int i=n-k+1;i<=n;i++) y[++num]=i;
            for(int i=1;i<=n;i++)
                if(sa[i]>k)
                    y[++num]=sa[i]-k;
            for(int i=1;i<=m;i++) c[i]=0;
            for(int i=1;i<=n;i++) c[x[i]]++;
            for(int i=2;i<=m;i++) c[i]+=c[i-1];
            for(int i=n;i;i--) sa[c[x[y[i]]]--]=y[i],y[i]=0;
            swap(x,y);
            x[sa[1]]=num=1;
            for(int i=2;i<=n;i++)
                x[sa[i]]=(y[sa[i]]==y[sa[i-1]] && y[sa[i]+k]==y[sa[i-1]+k])?num:++num;
            if(num==n) break;
            m=num;
        }
    }
    void get_height(){
        for(int i=1;i<=n;i++) rk[sa[i]]=i;
        for(int i=1,k=0;i<=n;i++){
            if(rk[i]==1){
                height[rk[i]]=k=0;
                continue;
            }
            k=max(0,k-1);
            int j=sa[rk[i]-1];
            while(i+k<=n && j+k<=n && s[i+k]==s[j+k]) k++;
            height[rk[i]]=k;
        }
    }
    void build(){
        get_sa();
        get_height();
        for(int i=1;i<=n;i++){
            f[i][0]=height[i];
            for(int j=1;(1<<j)<=i;j++)
                f[i][j]=min(f[i][j-1],f[i-(1<<j-1)][j-1]);
        }
    }
    int LCP(int x,int y){
        x=rk[x],y=rk[y];
        if(x>y) swap(x,y);
        int len=log2(y-x);
        return min(f[y][len],f[x+(1<<len)][len]);
    }
}S,P;

int main(){
    scanf("%d",&T);
    while(T--){
        scanf("%s",s+1);
        n=strlen(s+1);
        reverse(s+1,s+n+1);
        S.build();
        reverse(s+1,s+n+1);
        P.build();
        for(int i=1;i<=n;i++) f[i]=g[i]=0;
        for(int len=1;len<=n;len++)
            for(int i=len;i+len<=n;i+=len){
                int l=S.LCP(n-i+1,n-(i+len)+1),r=P.LCP(i,i+len);
                if(l+r>len){
                    f[max(i-len+1,i-l+1)]++;
                    f[min(i+1,i+r-len+1)]--;
                    g[max(i-len+1,i-l+1)+2*len-1]++;
                    g[min(i+1,i+r-len+1)+2*len-1]--;
                }
            }
        ans=0;
        for(int i=2;i<=n;i++){
            f[i]+=f[i-1];
            g[i]+=g[i-1];
            ans+=1ll*g[i-1]*f[i];
        }
        printf("%lld\n",ans);
    }
    return 0;
}
